#include <stdio.h>
#include <string.h>
int main() {
    int n;
    scanf("%d", &n);
    while (n--) {
        char s[101];
        scanf("%s", s);
        int len = strlen(s);
        int min_len = len;
        for (int i = 0; i < len; i++) {
            for (int j = i + 1; j <= len; j++) {
                char temp[101];
                strncpy(temp, s + i, j - i);
                temp[j - i] = '\0';
                int unique = 0;
                for (int k = 0; k < j - i; k++) {
                    int found = 0;
                    for (int l = 0; l < k; l++) {
                        if (temp[k] == temp[l]) {
                            found = 1;
                            break;
                        }
                    }
                    if (!found) unique++;
                }
                if (unique == strlen(temp)) {
                    if (j - i < min_len) min_len = j - i;
                }
            }
        }
        printf("%d\n", min_len);
    }
    return 0;
}

