def solve(s):
    n = len(s)
    min_len = n
    for i in range(n):
        for j in range(i + 1, n + 1):
            temp = s[i:j]
            unique = 0
            for k in range(len(temp)):
                found = False
                for l in range(k):
                    if temp[k] == temp[l]:
                        found = True
                        break
                if not found: unique += 1
            if unique == len(temp):
                if j - i < min_len: min_len = j - i
    return min_len

